type SourceCodeVerificationFlow =
    {
        /// The number of attempts remaining to authenticate the source object with a verification code.
        AttemptsRemaining: int
        /// The status of the code verification, either `pending` (awaiting verification, `attempts_remaining` should be greater than 0), `succeeded` (successful verification) or `failed` (failed verification, cannot be verified anymore as `attempts_remaining` should be 0).
        Status: string
    }

type Shipping =
    {
        Address: Address option
        /// The delivery service that shipped a physical product, such as Fedex, UPS, USPS, etc.
        Carrier: string option
        /// Recipient name.
        Name: string option
        /// Recipient phone (including extension).
        Phone: string option
        /// The tracking number for a physical product, obtained from the delivery service. If multiple tracking numbers were generated for this purchase, please separate them with commas.
        TrackingNumber: string option
    }

[<Struct>]
type SourceOrderItemType =
    | Sku
    | Tax
    | Shipping

type SourceOrderItem =
    {
        /// The amount (price) for this order item.
        Amount: int option
        /// This currency of this order item. Required when `amount` is present.
        Currency: IsoTypes.IsoCurrencyCode option
        /// Human-readable description for this order item.
        Description: string option
        /// The ID of the associated object for this line item. Expandable if not null (e.g., expandable to a SKU).
        Parent: string option
        /// The quantity of this order item. When type is `sku`, this is the number of instances of the SKU to be ordered.
        Quantity: int option
        /// The type of this order item. Must be `sku`, `tax`, or `shipping`.
        Type: SourceOrderItemType option
    }

type SourceOrder =
    {
        /// A positive integer in the smallest currency unit (that is, 100 cents for $1.00, or 1 for ¥1, Japanese Yen being a zero-decimal currency) representing the total amount for the order.
        Amount: int
        /// Three-letter [ISO currency code](https://www.iso.org/iso-4217-currency-codes.html), in lowercase. Must be a [supported currency](https://stripe.com/docs/currencies).
        Currency: IsoTypes.IsoCurrencyCode
        /// The email address of the customer placing the order.
        Email: string option
        /// List of items constituting the order.
        Items: SourceOrderItem list option
        Shipping: Shipping option
    }

type SourceOwner =
    {
        /// Owner's address.
        Address: Address option
        /// Owner's email address.
        Email: string option
        /// Owner's full name.
        Name: string option
        /// Owner's phone number (including extension).
        Phone: string option
        /// Verified owner's address. Verified values are verified or provided by the payment method directly (and if supported) at the time of authorization or settlement. They cannot be set or mutated.
        VerifiedAddress: Address option
        /// Verified owner's email address. Verified values are verified or provided by the payment method directly (and if supported) at the time of authorization or settlement. They cannot be set or mutated.
        VerifiedEmail: string option
