/// Customers with certain payments enabled have a cash balance, representing funds that were paid
/// by the customer to a merchant, but have not yet been allocated to a payment. Cash Balance Transactions
/// represent when funds are moved into or out of this balance. This includes funding by the customer, allocation
/// to payments, and refunds to the customer.
type CustomerCashBalanceTransaction =
    {
        AdjustedForOverdraft: CustomerBalanceResourceCashBalanceTransactionResourceAdjustedForOverdraft option
        AppliedToPayment: CustomerBalanceResourceCashBalanceTransactionResourceAppliedToPaymentTransaction option
        /// Time at which the object was created. Measured in seconds since the Unix epoch.
        Created: DateTime
        /// Three-letter [ISO currency code](https://www.iso.org/iso-4217-currency-codes.html), in lowercase. Must be a [supported currency](https://stripe.com/docs/currencies).
        Currency: IsoTypes.IsoCurrencyCode
        /// The customer whose available cash balance changed as a result of this transaction.
        Customer: StripeId<Markers.Customer>
        /// The ID of an Account representing a customer whose available cash balance changed as a result of this transaction.
        CustomerAccount: string option
        /// The total available cash balance for the specified currency after this transaction was applied. Represented in the [smallest currency unit](https://docs.stripe.com/currencies#zero-decimal).
        EndingBalance: int
        Funded: CustomerBalanceResourceCashBalanceTransactionResourceFundedTransaction option
        /// Unique identifier for the object.
        Id: string
        /// If the object exists in live mode, the value is `true`. If the object exists in test mode, the value is `false`.
        Livemode: bool
        /// The amount by which the cash balance changed, represented in the [smallest currency unit](https://docs.stripe.com/currencies#zero-decimal). A positive value represents funds being added to the cash balance, a negative value represents funds being removed from the cash balance.
        NetAmount: int
        RefundedFromPayment: CustomerBalanceResourceCashBalanceTransactionResourceRefundedFromPaymentTransaction option
        TransferredToBalance: CustomerBalanceResourceCashBalanceTransactionResourceTransferredToBalance option
        /// The type of the cash balance transaction. New types may be added in future. See [Customer Balance](https://docs.stripe.com/payments/customer-balance#types) to learn more about these types.
        Type: CustomerCashBalanceTransactionType
        UnappliedFromPayment:
            CustomerBalanceResourceCashBalanceTransactionResourceUnappliedFromPaymentTransaction option
    }

